const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);
const todayStr = today.toISOString().split('T')[0];
const results = [];

const sanitize = (s) => String(s || '').replace(/<[^>]*>/g, '').replace(/[`"\\]/g, '').trim();

for (const item of items) {
  const row = item.json;
  const status = String(row.status || '').trim().toUpperCase();
  if (status === 'PAID' || status === 'LEGAL_REVIEW') continue;

  // OPT: skip invoices already processed today — no duplicate emails, no wasted AI tokens
  if (String(row.last_sent_date || '').trim() === todayStr) continue;

  const dueDate = new Date(row.due_date);
  if (isNaN(dueDate)) continue;

  const daysOverdue = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
  if (daysOverdue <= 0) continue;

  const followUpCount = Number(row.follow_up_count) || 0;
  let stage;
  if (followUpCount >= 4 || daysOverdue >= 30) stage = 5;
  else if (daysOverdue <= 7) stage = 1;
  else if (daysOverdue <= 14) stage = 2;
  else if (daysOverdue <= 21) stage = 3;
  else stage = 4;

  results.push({
    json: {
      invoice_no: sanitize(row.invoice_no),
      client_name: sanitize(row.client_name),
      client_email: sanitize(row.client_email),
      amount_due: Number(row.amount_due),
      currency: sanitize(row.currency),
      due_date: sanitize(row.due_date),
      follow_up_count: followUpCount,
      payment_link: sanitize(row.payment_link),
      days_overdue: daysOverdue,
      stage,
      row_number: row._rowNumber || null
    }
  });
}

return results;

const items = $input.all();

// OPT: collect all stage-1..4 invoices into one item.
// Downstream AI node makes exactly ONE API call for the entire batch.
// Only send fields the AI actually needs — strips ~40% of token payload.
const invoices = items.map(item => ({
  invoice_no:   item.json.invoice_no,
  client_name:  item.json.client_name,
  client_email: item.json.client_email,
  amount_due:   item.json.amount_due,
  currency:     item.json.currency,
  due_date:     item.json.due_date,
  payment_link: item.json.payment_link,
  days_overdue: item.json.days_overdue,
  stage:        item.json.stage
}));

// _originals carries full data for downstream validation + sheet updates
return [{ json: { invoices, _originals: items.map(i => i.json) } }];

const CHUNK_SIZE = 10; // Adjust if needed. 10 is safe for all Gemini models.
const item = $input.first().json;
const invoices  = item.invoices;
const originals = item._originals;
const chunks = [];

for (let i = 0; i < invoices.length; i += CHUNK_SIZE) {
  chunks.push({
    json: {
      invoices:    invoices.slice(i, i + CHUNK_SIZE),
      _originals:  originals.slice(i, i + CHUNK_SIZE),
      chunkIndex:  Math.floor(i / CHUNK_SIZE),
      totalChunks: Math.ceil(invoices.length / CHUNK_SIZE)
    }
  });
}

return chunks;

parameters.text:
=Process ALL invoices in this batch. Return a results array with exactly one entry per invoice, in the same order as the input.

Invoices:
{{ JSON.stringify($json.invoices) }}

parameters.inputSchema:
{
  "type": "object",
  "additionalProperties": false,
  "required": ["results"],
  "properties": {
    "results": {
      "type": "array",
      "description": "One entry per invoice, in the same order as the input batch.",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["invoice_no", "subject", "body", "stage", "tone", "action", "confidence"],
        "properties": {
          "invoice_no": {
            "type": "string",
            "description": "Exact invoice number from the input — used to match this result back to the original record."
          },
          "subject": {
            "type": "string",
            "description": "Email subject line. Must include the invoice number."
          },
          "body": {
            "type": "string",
            "description": "Plain text email body containing all mandatory facts."
          },
          "stage": {
            "type": "integer",
            "minimum": 1,
            "maximum": 4,
            "description": "Must match the stage value from the input invoice exactly."
          },
          "tone": {
            "type": "string",
            "enum": ["Warm and Friendly", "Polite but Firm", "Formal and Serious", "Stern and Urgent"]
          },
          "action": {
            "type": "string",
            "enum": ["DRAFT_EMAIL"]
          },
          "confidence": {
            "type": "number",
            "minimum": 0,
            "maximum": 1
          }
        }
      }
    }
  }
}

