// Each item in $input corresponds to one AI Agent execution (one chunk).
// $('Split Into Chunks').all() gives the matching chunk originals in the same order.
const aiOutputItems  = $input.all();
const chunkItems     = $('Split Into Chunks').all();

if (aiOutputItems.length !== chunkItems.length) {
  throw new Error('AI batch validation failed');
}

const results = [];

for (let chunkIdx = 0; chunkIdx < aiOutputItems.length; chunkIdx++) {
  const raw       = aiOutputItems[chunkIdx].json;
  const output    = raw.output || raw;
  const aiResults = Array.isArray(output.results) ? output.results
                  : (Array.isArray(output) ? output : [output]);
  const originals = chunkItems[chunkIdx].json._originals;

  if (aiResults.length !== originals.length) {
    throw new Error('AI batch validation failed');
  }

  for (let i = 0; i < aiResults.length; i++) {
    const aiItem   = aiResults[i];
    // Match by invoice_no first; fall back to positional
    const original = originals.find(o => o.invoice_no === aiItem.invoice_no) || originals[i];

    // 1. Required fields present
    const requiredFields = ['subject', 'body', 'stage', 'tone', 'confidence'];
    for (const field of requiredFields) {
      if (aiItem[field] === undefined || aiItem[field] === null || aiItem[field] === '') {
        throw new Error('AI batch validation failed');
      }
    }

    // 2. Stage must be 1-4 (5 is routed out before AI ever sees it)
    const stageNum = Number(aiItem.stage);
    if (![1, 2, 3, 4].includes(stageNum)) {
      throw new Error('AI batch validation failed');
    }

    // 3. Stage parity — AI must not drift from what the classifier decided
    if (stageNum !== Number(original.stage)) {
      throw new Error('AI batch validation failed');
    }

    // 4. Fact-check — required facts must appear verbatim in subject+body
    const requiredFacts = [
      original.invoice_no,
      original.client_name,
      String(original.days_overdue),
      original.payment_link
    ];
    const haystack = `${aiItem.subject}\n${aiItem.body}`;
    for (const fact of requiredFacts) {
      if (!haystack.includes(String(fact))) {
        throw new Error('AI batch validation failed');
      }
    }

    // 5. Placeholder check
    if (String(aiItem.body).includes('{{') || String(aiItem.body).includes('[[')) {
      throw new Error('AI batch validation failed');
    }

    // 6. Confidence gate
    if (Number(aiItem.confidence) < 0.85) {
      throw new Error('AI batch validation failed');
    }

    results.push({ json: { ...original, ...aiItem } });
  }
}

return results;
